import json
from datetime import datetime

input_path = '/Users/rama/.nanobot/workspace/sessions/cli_direct.jsonl'
target_date = '2026-03-10'
target_dt = datetime.strptime(target_date, '%Y-%m-%d').date()

conversations = []
current_session = []

with open(input_path, 'r', encoding='utf-8') as f:
    for line in f:
        line = line.strip()
        if not line:
            continue
        try:
            data = json.loads(line)
            if data.get('_type') == 'metadata':
                continue
            role = data.get('role', '')
            if role not in ('user', 'assistant'):
                continue

            if target_dt and 'timestamp' in data:
                try:
                    msg_dt = datetime.fromisoformat(data['timestamp']).date()
                    if msg_dt != target_dt:
                        continue
                except Exception as e:
                    print(f'时间解析失败: {e}, timestamp={data.get(\"timestamp\")}')
                    continue

            current_session.append(data)

            if role == 'assistant' and current_session:
                has_user = any(m.get('role') == 'user' for m in current_session)
                if has_user:
                    conversations.append(current_session.copy())
                current_session = []
        except json.JSONDecodeError:
            continue

print(f'总对话数: {len(conversations)}')
for i, conv in enumerate(conversations):
    parts = []
    ts = None
    for msg in conv:
        role = msg.get('role', '')
        content = msg.get('content', '').strip()
        if role == 'user':
            parts.append(f'[用户] {content[:30]}...')
        elif role == 'assistant':
            parts.append(f'[AI] {content[:30]}...')
        if ts is None and 'timestamp' in msg:
            ts = msg['timestamp']
    content_len = sum(len(m.get('content', '')) for m in conv)
    print(f'{i+1}. 长度={content_len}, 时间={ts}, 内容={\" \".join(parts)}')
